import{_ as e,o as n,c as i,ag as a}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"03 — Personas & User Journey","description":"","frontmatter":{},"headers":[],"relativePath":"00-san-pham/03-personas-user-journey.md","filePath":"00-san-pham/03-personas-user-journey.md"}'),o={name:"00-san-pham/03-personas-user-journey.md"};function r(d,t,l,s,h,c){return n(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="_03-—-personas-user-journey" tabindex="-1">03 — Personas &amp; User Journey <a class="header-anchor" href="#_03-—-personas-user-journey" aria-label="Permalink to &quot;03 — Personas &amp; User Journey&quot;">​</a></h1><blockquote><p><strong>Vai trò đọc</strong>: PO, BA, designer, dev — biết &quot;đang code cho ai&quot; trước khi viết feature. <strong>Quy tắc</strong>: mỗi feature trong sprint phải serve ít nhất 1 persona. Không serve persona nào → tech-debt cleanup hoặc cần review.</p></blockquote><blockquote><p>Persona đặt tên người Việt cụ thể (Anh Khoa, Chị Linh, Admin Vivu) để team dễ empathy. Không dùng tên abstract &quot;User A / User B&quot;.</p></blockquote><hr><h2 id="_1-ba-personas-chinh" tabindex="-1">1. Ba personas chính <a class="header-anchor" href="#_1-ba-personas-chinh" aria-label="Permalink to &quot;1. Ba personas chính&quot;">​</a></h2><h3 id="_1-1-anh-khoa-—-family-decision-maker-primary-persona" tabindex="-1">1.1 Anh Khoa — Family Decision Maker (Primary persona) <a class="header-anchor" href="#_1-1-anh-khoa-—-family-decision-maker-primary-persona" aria-label="Permalink to &quot;1.1 Anh Khoa — Family Decision Maker (Primary persona)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thuộc tính</th><th>Mô tả</th></tr></thead><tbody><tr><td>Tuổi / Nghề</td><td>32 tuổi, Kỹ sư phần mềm, TP.HCM</td></tr><tr><td>Gia đình</td><td>Vợ 29t + 2 con (6t, 3t), thỉnh thoảng dẫn ba mẹ đi cùng</td></tr><tr><td>Thu nhập</td><td>30-50tr/tháng, ngân sách du lịch ~50tr/năm</td></tr><tr><td>Tần suất</td><td>2-3 lần/năm (hè, Tết, lễ dài)</td></tr><tr><td>Tech savvy</td><td>Cao — quen Google + Klook + Airbnb</td></tr><tr><td>Device</td><td>Desktop khi research, mobile khi book/xem nhanh</td></tr><tr><td>Kênh discover</td><td>Google search &quot;tour [địa điểm] [N ngày] gia đình&quot;, group FB &quot;Du lịch cùng con&quot;</td></tr></tbody></table><p><strong>Pain points:</strong></p><ul><li>Sợ tour &quot;treo đầu dê bán thịt chó&quot; (mô tả khác thực tế)</li><li>Phải gọi/chat operator nhiều mới chốt được giá</li><li>Lo trẻ con không hợp lịch trình (đi quá nhiều)</li><li>Sợ chuyển khoản tay không an toàn</li></ul><p><strong>Goals:</strong></p><ul><li>Tìm tour 4-6 ngày phù hợp gia đình có trẻ nhỏ</li><li>So sánh 3-4 option nhanh</li><li>Book online minh bạch, có hoá đơn</li></ul><p><strong>Behavior:</strong></p><ul><li>Đọc kỹ itinerary từng ngày</li><li>Filter theo &quot;phù hợp trẻ em&quot;, &quot;hotel 4★+&quot;</li><li>Đọc review verified (đặc biệt review có ảnh)</li><li>Tham khảo vợ trước khi book → cần share link tour</li></ul><p><strong>Quote:</strong></p><blockquote><p><em>&quot;Tôi muốn biết rõ mỗi ngày con tôi sẽ đi đâu, ăn gì, ngủ ở đâu — trước khi tôi quyết chi 30 triệu.&quot;</em></p></blockquote><p><strong>Feature ưu tiên cho Anh Khoa:</strong></p><ul><li>Detail page: gallery thực + itinerary từng ngày + thông tin hotel cụ thể + policy trẻ em + review verified</li><li>Filter &quot;phù hợp gia đình&quot;, &quot;có trẻ em&quot;, &quot;hotel ≥4★&quot;</li><li>Share link tour với OG image đẹp (preview khi paste Zalo/FB)</li><li>Payment chính thống (VNPay/MoMo) + email hoá đơn</li></ul><hr><h3 id="_1-2-chi-linh-—-young-professional-couple-traveler" tabindex="-1">1.2 Chị Linh — Young Professional / Couple Traveler <a class="header-anchor" href="#_1-2-chi-linh-—-young-professional-couple-traveler" aria-label="Permalink to &quot;1.2 Chị Linh — Young Professional / Couple Traveler&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thuộc tính</th><th>Mô tả</th></tr></thead><tbody><tr><td>Tuổi / Nghề</td><td>28 tuổi, Marketing Manager, Hà Nội</td></tr><tr><td>Gia đình</td><td>Single hoặc đi cùng bạn trai / nhóm bạn 4-6 người</td></tr><tr><td>Thu nhập</td><td>20-30tr/tháng, ngân sách du lịch ~30tr/năm</td></tr><tr><td>Tần suất</td><td>3-5 lần/năm (weekend escape + 1 chuyến lớn)</td></tr><tr><td>Tech savvy</td><td>Rất cao — mobile-first, IG/TikTok heavy user</td></tr><tr><td>Device</td><td>Mobile 80% — search, book, share đều trên điện thoại</td></tr><tr><td>Kênh discover</td><td>Instagram explore, TikTok aesthetic, Google quick search</td></tr></tbody></table><p><strong>Pain points:</strong></p><ul><li>Web travel tiếng Việt UX cũ, không mobile-friendly</li><li>Tour package thường rườm rà với người không có gia đình</li><li>Muốn flexibility (đổi ngày/hotel) nhưng operator không cho</li></ul><p><strong>Goals:</strong></p><ul><li>Tìm weekend trip 2-3 ngày, vibe đẹp để post IG</li><li>Book nhanh trên mobile</li><li>Save trip &quot;để xem sau&quot;</li></ul><p><strong>Behavior:</strong></p><ul><li>Lướt nhanh, scan ảnh nhiều hơn đọc</li><li>Search by mood (&quot;núi rừng&quot;, &quot;biển vắng&quot;, &quot;phố cổ&quot;)</li><li>Quan tâm review về ảnh đẹp + food + nightlife</li><li>Hay save trip rồi 1-2 tuần sau mới quyết</li></ul><p><strong>Quote:</strong></p><blockquote><p><em>&quot;Tôi muốn tour mà 30 giây nhìn ảnh là đã muốn book ngay, không phải đọc 5 trang mô tả.&quot;</em></p></blockquote><p><strong>Feature ưu tiên cho Chị Linh:</strong></p><ul><li>Mobile-first responsive cực ngon, hero image rich</li><li>Discovery theo &quot;vibe&quot; / collection (không chỉ filter địa lý)</li><li>Save/Wishlist (Phase 1 có thể defer → bookmark browser)</li><li>Booking flow tối ưu mobile (max 3 step, autofill, no friction)</li><li>Share preview đẹp (OG image dynamic per tour)</li></ul><hr><h3 id="_1-3-admin-vivu-—-internal-operator-special-persona" tabindex="-1">1.3 Admin Vivu — Internal Operator (Special persona) <a class="header-anchor" href="#_1-3-admin-vivu-—-internal-operator-special-persona" aria-label="Permalink to &quot;1.3 Admin Vivu — Internal Operator (Special persona)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thuộc tính</th><th>Mô tả</th></tr></thead><tbody><tr><td>Vai trò</td><td>Operator nội bộ Vivu (Content / Ops / Founder kiêm)</td></tr><tr><td>Số lượng dự kiến</td><td>3-5 người Phase 1</td></tr><tr><td>Tech savvy</td><td>TB-cao — quen WordPress, Excel, Google Sheets</td></tr><tr><td>Device</td><td>Desktop ~90%, đôi khi tablet</td></tr><tr><td>Kênh</td><td>Trực tiếp vào <code>/portal/*</code> (admin zone)</td></tr></tbody></table><p><strong>Pain points:</strong></p><ul><li>CMS rườm rà, nhiều click để tạo 1 tour</li><li>Không biết ai sửa nội dung khi (cần audit log)</li><li>Upload ảnh chậm hoặc fail</li><li>Lỡ tay xoá tour/destination không khôi phục được</li><li>Không biết tour nào đang bán chạy</li></ul><p><strong>Goals:</strong></p><ul><li>Tạo / cập nhật tour nhanh, ít click</li><li>Theo dõi booking realtime</li><li>Quản lý lịch khởi hành + slot còn lại</li><li>Update SEO không cần dev support</li></ul><p><strong>Behavior:</strong></p><ul><li>Mỗi ngày check booking + email khách</li><li>Mỗi tuần publish 2-3 tour mới hoặc update</li><li>Mỗi tháng review SEO ranking + traffic</li></ul><p><strong>Quote:</strong></p><blockquote><p><em>&quot;Tôi muốn tạo 1 tour trong 5 phút, sửa ảnh trong 1 phút, và biết ngay tour nào đang được khách quan tâm nhất tuần này.&quot;</em></p></blockquote><p><strong>Feature ưu tiên cho Admin Vivu:</strong></p><ul><li>Form CMS có validation Zod + toast error rõ ràng</li><li>Bulk upload ảnh Cloudinary + drag-reorder</li><li>Audit log (<code>ActivityLog</code>) cho mọi mutation</li><li>Soft delete bằng <code>isActive</code> (không xoá cứng)</li><li>Dashboard L0: booking hôm nay, doanh thu tuần, tour hot</li><li>SEO override per entity (<code>SeoPage</code> polymorphic)</li></ul><hr><h2 id="_2-user-journey-—-anh-khoa-book-tour-gia-đinh" tabindex="-1">2. User Journey — Anh Khoa book tour gia đình <a class="header-anchor" href="#_2-user-journey-—-anh-khoa-book-tour-gia-đinh" aria-label="Permalink to &quot;2. User Journey — Anh Khoa book tour gia đình&quot;">​</a></h2><blockquote><p><strong>Happy path B2C</strong> — phải tối ưu cho 90% case. Edge case ở mục 4.</p></blockquote><h3 id="_2-1-journey-overview" tabindex="-1">2.1 Journey overview <a class="header-anchor" href="#_2-1-journey-overview" aria-label="Permalink to &quot;2.1 Journey overview&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐   ┌──────────┐   ┌──────────┐   ┌──────────┐   ┌──────────┐</span></span>
<span class="line"><span>│ DISCOVER │ → │  BROWSE  │ → │  DETAIL  │ → │   BOOK   │ → │   POST   │</span></span>
<span class="line"><span>└──────────┘   └──────────┘   └──────────┘   └──────────┘   └──────────┘</span></span>
<span class="line"><span>   Google         Filter         Gallery        Form           Email</span></span>
<span class="line"><span>   Social         List           Itinerary      Payment        Tour</span></span>
<span class="line"><span>   Direct         Sort           Hotel info     Confirm        Review</span></span>
<span class="line"><span>                                 Review</span></span></code></pre></div><h3 id="_2-2-journey-chi-tiet-touchpoint-×-emotion-×-backend" tabindex="-1">2.2 Journey chi tiết (touchpoint × emotion × backend) <a class="header-anchor" href="#_2-2-journey-chi-tiet-touchpoint-×-emotion-×-backend" aria-label="Permalink to &quot;2.2 Journey chi tiết (touchpoint × emotion × backend)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Bước</th><th>Touchpoint</th><th>Emotion</th><th>Backend cần</th></tr></thead><tbody><tr><td>1. Discover</td><td>Google search → click Vivu</td><td>Curious</td><td>SEO metadata + structured data + sitemap</td></tr><tr><td>2. Browse</td><td><code>/tours</code> lọc destination + giá + thời gian + &quot;gia đình&quot;</td><td>Comparing</td><td><code>TourService.searchListings</code>, filter index, cache</td></tr><tr><td>3. Detail</td><td><code>/tours/[slug]</code> xem gallery, itinerary, hotel, review</td><td>Considering</td><td><code>TourService.getBySlug</code> + itinerary + hotel + review verified</td></tr><tr><td>3.5 Compare</td><td>Mở 2-3 tab, share link cho vợ qua Zalo</td><td>Validating</td><td>OG image dynamic, page load nhanh</td></tr><tr><td>4. Pick date</td><td>Chọn departure còn slot</td><td>Deciding</td><td><code>TourDeparture</code> với slot availability, anti-overbook</td></tr><tr><td>5. Login</td><td>Redirect đăng nhập / đăng ký (must-login)</td><td>Slight friction</td><td>Auth flow tối ưu — Google OAuth 1-click</td></tr><tr><td>6. Booking form</td><td>Điền tên/SDT/email/số người/ghi chú</td><td>Focused</td><td>Validation Zod + pre-fill profile, snapshot pricing</td></tr><tr><td>7. Payment</td><td>VNPay / MoMo redirect, trả tiền, redirect back</td><td>Anxious</td><td>Payment service, webhook idempotency, transaction safety</td></tr><tr><td>8. Confirmation</td><td>Trang cảm ơn + email + mã đơn</td><td>Relief</td><td>Email transactional, <code>Booking</code> saved, <code>ActivityLog</code></td></tr><tr><td>9. Pre-tour</td><td>Email reminder 7 ngày + 1 ngày trước</td><td>Excited</td><td>Cron / scheduled email</td></tr><tr><td>10. Tour</td><td>Đi thực tế</td><td>(offline)</td><td>—</td></tr><tr><td>11. Post-tour</td><td>Email mời review verified</td><td>Satisfied / Disappointed</td><td>Review service (chỉ user <code>COMPLETED</code> booking)</td></tr></tbody></table><h3 id="_2-3-hotspot-—-cho-de-rot-drop-off" tabindex="-1">2.3 Hotspot — chỗ dễ rớt (drop-off) <a class="header-anchor" href="#_2-3-hotspot-—-cho-de-rot-drop-off" aria-label="Permalink to &quot;2.3 Hotspot — chỗ dễ rớt (drop-off)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Phase</th><th>Drop-off risk</th><th>Mitigation Phase 1</th></tr></thead><tbody><tr><td>Browse → Detail</td><td>Page load chậm</td><td>SSR/ISR + image optimize</td></tr><tr><td>Detail → Pick date</td><td>Không có departure phù hợp</td><td>Suggest departure khác / destination tương tự</td></tr><tr><td>Pick date → Login</td><td><strong>Cao nhất</strong> — friction must-login</td><td>Google OAuth 1-click, save state khi login để không mất context</td></tr><tr><td>Form → Payment</td><td>Form quá dài / lỗi validation</td><td>Pre-fill từ profile, realtime validation, error rõ</td></tr><tr><td>Payment → Confirm</td><td>VNPay timeout / huỷ</td><td>Webhook retry + status PENDING + email recovery</td></tr></tbody></table><hr><h2 id="_3-service-blueprint-—-booking-flow" tabindex="-1">3. Service Blueprint — Booking flow <a class="header-anchor" href="#_3-service-blueprint-—-booking-flow" aria-label="Permalink to &quot;3. Service Blueprint — Booking flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ FRONTSTAGE (Customer thấy)                                          │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  Detail page → Booking widget → Form modal → Payment redirect       │</span></span>
<span class="line"><span>│      ↓              ↓                ↓               ↓              │</span></span>
<span class="line"><span>│ ════════════════════════════════════════════════════════════════════│</span></span>
<span class="line"><span>│ BACKSTAGE (Vivu xử lý)                                              │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  TourService    BookingService    AuthCheck    Payment Provider     │</span></span>
<span class="line"><span>│  .getBySlug    .createBooking    requireUser   VNPay/MoMo SDK       │</span></span>
<span class="line"><span>│      ↓              ↓                ↓               ↓              │</span></span>
<span class="line"><span>│  Prisma query  Pessimistic lock  Supabase     Webhook listener      │</span></span>
<span class="line"><span>│                TourDeparture     session      update status         │</span></span>
<span class="line"><span>│      ↓              ↓                ↓               ↓              │</span></span>
<span class="line"><span>│ ════════════════════════════════════════════════════════════════════│</span></span>
<span class="line"><span>│ SUPPORT (Cross-cutting)                                             │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  i18n message · ActivityLog · Email service · Cache invalidation    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="_4-edge-cases-failure-modes" tabindex="-1">4. Edge cases &amp; failure modes <a class="header-anchor" href="#_4-edge-cases-failure-modes" aria-label="Permalink to &quot;4. Edge cases &amp; failure modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Behavior cần có Phase 1</th></tr></thead><tbody><tr><td>2 khách book cùng 1 slot cuối</td><td>Pessimistic lock → 1 win + 1 báo &quot;hết slot, chọn departure khác&quot;</td></tr><tr><td>Payment VNPay timeout</td><td>Booking PENDING → email &quot;thử lại&quot; + admin thấy trong dashboard</td></tr><tr><td>Khách book xong muốn huỷ</td><td>Phase 1: form contact admin; Phase 1.5: self-service theo policy</td></tr><tr><td>Khách quên password</td><td>Forgot password flow đã có</td></tr><tr><td>Admin xoá tour có booking pending</td><td>Block xoá (FK constraint) hoặc soft delete <code>isActive=false</code></td></tr><tr><td>Admin xoá destination</td><td>Cascade hide cả tour/hotel xuống public</td></tr><tr><td>SEO: tour đổi slug</td><td><code>SeoPage</code> polymorphic theo entity ID → không orphan</td></tr><tr><td>Email khách không đến</td><td>Resend từ admin dashboard</td></tr><tr><td>Tour đang chạy hotel huỷ allotment</td><td>Manual: admin liên hệ khách swap hotel; không tự động</td></tr></tbody></table><hr><h2 id="_5-persona-→-feature-priority-matrix" tabindex="-1">5. Persona → Feature priority matrix <a class="header-anchor" href="#_5-persona-→-feature-priority-matrix" aria-label="Permalink to &quot;5. Persona → Feature priority matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th style="text-align:center;">Anh Khoa</th><th style="text-align:center;">Chị Linh</th><th style="text-align:center;">Admin Vivu</th></tr></thead><tbody><tr><td>Tour list + filter</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td></tr><tr><td>Tour detail gallery</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">—</td></tr><tr><td>Itinerary từng ngày</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td></tr><tr><td>Hotel info trong tour</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td></tr><tr><td>Filter &quot;phù hợp gia đình&quot;</td><td style="text-align:center;">🟢</td><td style="text-align:center;">⚪</td><td style="text-align:center;">—</td></tr><tr><td>Mobile-first responsive</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td></tr><tr><td>OG image dynamic</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td><td style="text-align:center;">—</td></tr><tr><td>Save / Wishlist</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td><td style="text-align:center;">—</td></tr><tr><td>Payment chính thống</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td></tr><tr><td>Email confirm + reminder</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td></tr><tr><td>Review verified</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td></tr><tr><td>Audit log</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">🟢</td></tr><tr><td>SEO override per entity</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">🟢</td></tr><tr><td>Loyalty point (P1.5)</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td></tr></tbody></table><p>Legend: 🟢 critical · 🟡 nice-to-have · ⚪ không cần · — không áp dụng</p><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Vision: <code>01-tam-nhin.md</code></li><li>Mô hình kinh doanh: <code>02-mo-hinh-kinh-doanh.md</code></li><li>Lộ trình: <code>04-lo-trinh-phat-hanh.md</code></li><li>Ma trận tính năng tổng: <code>../01-nghiep-vu/04-ma-tran-tinh-nang.md</code></li></ul>`,65)])])}const g=e(o,[["render",r]]);export{u as __pageData,g as default};
